class Solution {
    public int minimumScore(String s, String t) {
        int score = 0;
        int left = -1;
        int right = -1;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == t.charAt(0)) {
                left = 0;
                for (int j = 1; j < t.length(); j++) {
                    if (s.charAt(i + j) == t.charAt(j)) {
                        left = j;
                    } else {
                        left = -1;
                        break;
                    }
                }
                if (left != -1) {
                    right = i + t.length() - 1;
                    score = Math.min(score, right - left + 1);
                }
            }
        }
        return score == 0 ? 0 : score;
    }
}
